class Solution:
    def sortVowels(self, s):
        vowel_set = set('aeiou')
        positions = [i for i, ch in enumerate(s) if ch in vowel_set]
        chars = [s[i] for i in positions]
        freq = {}
        first_occ = {}
        for idx, ch in enumerate(chars):
            freq[ch] = freq.get(ch, 0) + 1
            if ch not in first_occ:
                first_occ[ch] = idx
        sorted_chars = sorted(chars, key=lambda c: (-freq[c], first_occ[c]))
        result = list(s)
        for pos, ch in zip(positions, sorted_chars):
            result[pos] = ch
        return ''.join(result)

