class Solution:
    def sortVowels(self, s: str) -> str:
        vowels_set = set('aeiou')
        freq = {}
        order = []
        for ch in s:
            if ch in vowels_set:
                if ch not in freq:
                    freq[ch] = 0
                    order.append(ch)
                freq[ch] += 1
        order.sort(key=lambda c: -freq[c])
        seq = []
        for ch in order:
            seq.extend([ch] * freq[ch])
        it = iter(seq)
        result = []
        for ch in s:
            if ch in vowels_set:
                result.append(next(it))
            else:
                result.append(ch)
        return ''.join(result)

