var sortVowels = function(s) {
    const vowelSet = new Set(['a', 'e', 'i', 'o', 'u']);
    const freq = new Map();
    const order = [];
    for (const ch of s) {
        if (vowelSet.has(ch)) {
            if (!freq.has(ch)) {
                freq.set(ch, 0);
                order.push(ch);
            }
            freq.set(ch, freq.get(ch) + 1);
        }
    }
    order.sort((a, b) => freq.get(b) - freq.get(a));
    const seq = [];
    for (const ch of order) {
        for (let i = 0; i < freq.get(ch); i++) seq.push(ch);
    }
    let idx = 0;
    const result = [];
    for (const ch of s) {
        if (vowelSet.has(ch)) {
            result.push(seq[idx]);
            idx++;
        } else {
            result.push(ch);
        }
    }
    return result.join('');
};
